components.css:
table {
  width: 100%;
  border-collapse: collapse;
  background: var(--a-surface-raised);
  border: 1px solid var(--a-border);
  border-radius: var(--a-radius-md);
  overflow: hidden;
}

th {
  background: var(--a-surface-overlay);
  padding: var(--a-space-md);
  text-align: left;
  font-weight: var(--a-font-weight-semibold);
  border-bottom: 2px solid var(--a-border-strong);
}

td {
  padding: var(--a-space-md);
  border-bottom: 1px solid var(--a-border);
}

tbody tr:hover {
  background: var(--a-surface-overlay);
}

ul {
  list-style: disc;
  margin: var(--a-space-md) 0;
  padding-left: var(--a-space-lg);
}

li {
  margin-bottom: var(--a-space-sm);
  line-height: var(--a-line-height-normal);
}

ol {
  list-style: decimal;
  margin: var(--a-space-md) 0;
  padding-left: var(--a-space-lg);
}

li {
  margin-bottom: var(--a-space-sm);
  line-height: var(--a-line-height-normal);
}

dl {
  margin: var(--a-space-md) 0;
}

dt {
  font-weight: var(--a-font-weight-semibold);
  margin-top: var(--a-space-md);
  margin-bottom: var(--a-space-xs);
}

dd {
  margin-left: var(--a-space-lg);
  margin-bottom: var(--a-space-sm);
  color: var(--a-text-secondary);
}

.stats-grid {
  display: grid;
  gap: var(--a-space-lg);
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
}

.stats-grid article {
  text-align: center;
  padding: var(--a-space-lg);
  background: var(--a-surface-overlay);
  border-radius: var(--a-radius-md);
}

.stats-grid h3 {
  margin: 0;
  font-size: var(--a-text-2xl);
  color: var(--a-primary);
}

.stats-grid p {
  margin: var(--a-space-sm) 0 0 0;
  color: var(--a-text-secondary);
}

.timeline {
  list-style: none;
  padding: 0;
  margin: var(--a-space-lg) 0;
}

.timeline li {
  padding-left: var(--a-space-2xl);
  margin-bottom: var(--a-space-lg);
  position: relative;
}

.timeline li::before {
  content: '';
  position: absolute;
  left: 0;
  top: 0;
  width: 12px;
  height: 12px;
  background: var(--a-primary);
  border-radius: 50%;
  border: 3px solid var(--a-surface-base);
}

.timeline li::after {
  content: '';
  position: absolute;
  left: 5px;
  top: 12px;
  width: 2px;
  height: calc(100% + var(--a-space-lg));
  background: var(--a-border);
}

.timeline li:last-child::after {
  display: none;
}

table {
  width: 100%;
  border-collapse: collapse;
  background: var(--a-surface-raised);
  border: 1px solid var(--a-border);
  border-radius: var(--a-radius-md);
}

th, td {
  padding: var(--a-space-md);
  border: 1px solid var(--a-border);
  text-align: center;
}

th {
  background: var(--a-surface-overlay);
  font-weight: var(--a-font-weight-semibold);
}

tbody tr:nth-child(even) {
  background: var(--a-surface-overlay);
}
